select.if:
/* UsgAmntMapper.getUsgAmntStatOrgListExcel */ SELECT B.CONTRACT_NUM AS contractNum , B.SUB_LINK_NAME AS custNm , B.SUBSCRIBER_NO AS subscriberNo , B.SUB_STATUS AS subStatus , FN_GET_CODENM('MSP0003', B.SUB_STATUS) AS subStatusNm , B.LST_COM_ACTV_DATE AS openDt , DECODE(B.SUB_STATUS, 'C', SUBSTR(B.SUB_STATUS_DATE, 1, 8), '') AS tmntDt , B.OPEN_AGNT_CD AS openAgntCd , FN_GET_ORGNM(B.OPEN_AGNT_CD) AS openAgntNm , A.VC_USG_AMNT + A.SC_USG_AMNT AS callUsgAmnt , A.VC_FREE_AMNT + A.SC_FREE_AMNT AS callFreeAmnt , A.VC_OVER_AMNT + A.SC_OVER_AMNT AS callOverAmnt , A.SMS_USG_CNT + A.MMS_USG_CNT + A.LMS_USG_CNT AS charUsgCnt , A.SMS_FREE_CNT + A.MMS_FREE_CNT + A.LMS_FREE_CNT AS charFreeCnt , A.SMS_OVER_CNT + A.MMS_OVER_CNT + A.LMS_OVER_CNT AS charOverCnt , ROUND(A.DATA_USG_AMNT * 512 / 1024 / 1024, 2) AS dataUsgAmnt , ROUND(A.DATA_FREE_AMNT * 512 / 1024 / 1024, 2) AS dataFreeAmnt , ROUND(A.DATA_OVER_AMNT * 512 / 1024 / 1024, 2) AS dataOverAmnt , A.ROAM_USG_AMNT AS roamUsgAmnt , A.ROAM_FREE_AMNT AS roamFreeAmnt , A.ROAM_OVER_AMNT AS roamOverAmnt , B.BAN AS ban FROM MSP_USG_AMNT_STTC A , MSP_JUO_SUB_INFO B WHERE A.USG_YM = #{usgYm} AND SUBSTR(B.LST_COM_ACTV_DATE,1,6) = #{openYm} AND A.CONTRACT_NUM = B.CONTRACT_NUM AND B.PPPO = 'PO'
AND (A.CONTRACT_NUM = #{searchVal} OR A.CONTRACT_NUM = (SELECT DISTINCT CONTRACT_NUM FROM MSP_JUO_SUB_INFO_HIST WHERE SVC_CNTR_NO = #{searchVal}))
AND B.SUB_LINK_NAME LIKE '%' || #{searchVal} || '%'
AND B.SUBSCRIBER_NO = #{searchVal}
AND B.OPEN_AGNT_CD = #{orgnId}
